const cfg = $('Set Config').first().json;

const safeGet = (n) => {
  try {
    const j = $(n).first().json;
    if (j?.error || j?.statusCode >= 400) return null;
    return j;
  } catch { return null; }
};

const safeGetAll = (n) => {
  try {
    return $(n).all().map(i => i.json).filter(j => j && !j.error && !(j.statusCode >= 400));
  } catch { return []; }
};

const fmtSeconds = (s) => {
  if (!s || isNaN(s)) return 'N/A';
  s = Math.round(s);
  if (s < 60) return s + 's';
  if (s < 3600) return Math.floor(s/60) + 'm ' + (s%60) + 's';
  return Math.floor(s/3600) + 'h ' + Math.floor((s%3600)/60) + 'm';
};

const dedupeByTs = (arr) => {
  const seen = new Set();
  return arr.filter(x => { const k = x?.timestamp ?? x?.date; if (seen.has(k)) return false; seen.add(k); return true; });
};

const summary    = safeGet('Fetch Account Summary');
const convVolume = dedupeByTs(safeGetAll('Fetch Conv Volume'));
const resTrend   = dedupeByTs(safeGetAll('Fetch Resolution Trend'));

const csatRaw       = safeGet('Fetch CSAT Reports');
const csatRows      = Array.isArray(csatRaw?.data) ? csatRaw.data : [];
const csatIsMetrics = csatRaw && csatRaw.total_count !== undefined;
const totalR   = csatIsMetrics ? (csatRaw.total_count ?? 0) : csatRows.length;
const posCount = csatIsMetrics ? (csatRaw.ratings?.Satisfied ?? 0) : csatRows.filter(r=>r.rating>=4).length;
const negCount = csatIsMetrics ? (csatRaw.ratings?.Dissatisfied ?? 0) : csatRows.filter(r=>r.rating<=2).length;
const sumR     = csatIsMetrics ? 0 : csatRows.reduce((a,r) => a+(r.rating??0), 0);

return [{ json: {
  meta: {
    generatedAt: new Date().toISOString(),
    period: { since: cfg.since, until: cfg.until, groupBy: cfg.groupBy }
  },
  summary: {
    totalConversations: summary?.conversations_count ?? 0,
    resolved:           summary?.resolutions_count ?? 0,
    incomingMessages:   summary?.incoming_messages_count ?? 0,
    outgoingMessages:   summary?.outgoing_messages_count ?? 0,
    avgFirstResponse:   fmtSeconds(summary?.avg_first_response_time),
    avgResolutionTime:  fmtSeconds(summary?.avg_resolution_time),
    replyTime:          fmtSeconds(summary?.reply_time)
  },
  charts: {
    conversationVolume: convVolume.map(p=>({ date: new Date(p.timestamp*1000).toLocaleDateString('en-US',{hour:'2-digit',hour12:false}), value: p.value })),
    resolutionTrend:    resTrend.map(p=>({ date: new Date(p.timestamp*1000).toLocaleDateString('en-US',{hour:'2-digit',hour12:false}), value: p.value }))
  },
  csat: {
    score:      totalR>0 ? Math.round((posCount/totalR)*100) : null,
    avgRating:  (!csatIsMetrics && totalR>0) ? parseFloat((sumR/totalR).toFixed(1)) : null,
    totalResponses: totalR,
    positive: posCount,
    negative: negCount,
    neutral:  csatIsMetrics ? (csatRaw.ratings?.Neutral ?? 0) : csatRows.filter(r=>r.rating===3).length,
    ratingDistribution: csatIsMetrics
      ? [
          { label: 'Satisfied',    count: csatRaw.ratings?.Satisfied    ?? 0, pct: totalR>0?Math.round((csatRaw.ratings?.Satisfied??0)/totalR*100):0 },
          { label: 'Neutral',      count: csatRaw.ratings?.Neutral      ?? 0, pct: totalR>0?Math.round((csatRaw.ratings?.Neutral??0)/totalR*100):0 },
          { label: 'Dissatisfied', count: csatRaw.ratings?.Dissatisfied ?? 0, pct: totalR>0?Math.round((csatRaw.ratings?.Dissatisfied??0)/totalR*100):0 }
        ]
      : [5,4,3,2,1].map(star=>({
          stars: star,
          count: csatRows.filter(r=>r.rating===star).length,
          pct:   totalR>0?Math.round(csatRows.filter(r=>r.rating===star).length/totalR*100):0
        })),
    recentResponses: csatRows.slice(0,50).map(r=>({
      rating: r.rating, feedback: r.feedback_message,
      agent:   r.assigned_agent?.name ?? 'Unassigned',
      contact: r.contact?.name ?? 'Unknown', createdAt: r.created_at
    }))
  }
}}];

const newMetrics = $('Build Metrics').first().json;

let existing = {};
try {
  const d = $('Read Drive for Merge').first().json;
  if (d && !d.error && !d.statusCode) existing = d;
} catch(e) {}

const now = new Date();
return [{ json: {
  // Preserve static data from last daily run
  agents:    existing.agents   ?? [],
  teams:     existing.teams    ?? [],
  labels:    existing.labels   ?? [],
  inboxes:   existing.inboxes  ?? [],
  _staticAt: existing._staticAt ?? null,

  // Replace with fresh metrics
  ...newMetrics,
  _metricsAt:   now.toISOString(),
  _savedAt:     now.toISOString(),
  _nextRefresh: new Date(now.getTime() + 60 * 60 * 1000).toISOString()
}}];

const data = $input.first().json;

if (!data || !data._savedAt) {
  return [{ json: {
    _cacheStatus: 'missing',
    _cacheError: 'Drive file is empty. Run "Chatwoot – Metrics" and "Chatwoot – Static Data" workflows manually once each.'
  }}];
}

const ageMs      = Date.now() - new Date(data._savedAt).getTime();
const ageMinutes = Math.floor(ageMs / 60000);
const isStale    = ageMs > 2 * 60 * 60 * 1000;

return [{ json: {
  ...data,
  _cache: {
    status:      isStale ? 'stale' : 'fresh',
    cachedAt:    data._savedAt,
    nextRefresh: data._nextRefresh,
    ageMinutes,
    metricsAt:   data._metricsAt ?? null,
    staticAt:    data._staticAt  ?? null
  }
}}];

const data = $input.first().json;
const esc = (s) => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

if (!data || !data._savedAt) {
  const html = `<!DOCTYPE html><html><head><title>Cache Status</title><style>body{font-family:sans-serif;padding:40px;background:#1a1a2e;color:#eee}h1{color:#e74c3c}.card{background:#2d2d44;padding:20px;border-radius:8px;border-left:4px solid #e74c3c}</style></head><body><h1>Cache Status</h1><div class="card"><strong>Drive file is empty.</strong><br><br>Run both workflows manually once:<br><ol><li>"Chatwoot – Metrics" → Run Manually</li><li>"Chatwoot – Static Data" → Run Manually</li></ol></div></body></html>`;
  return [{ json: { html } }];
}

const ageMs = Date.now() - new Date(data._savedAt).getTime();
const ageMinutes = Math.floor(ageMs / 60000);
const isStale = ageMs > 2 * 60 * 60 * 1000;
const sc = isStale ? '#e67e22' : '#2ecc71';
const sl = isStale ? 'STALE' : 'FRESH';
const summary = data.summary ?? {};
const sz = Math.round(JSON.stringify(data).length / 1024);

const html = `<!DOCTYPE html><html><head><title>Chatwoot Cache Status</title><style>body{font-family:sans-serif;padding:40px;background:#1a1a2e;color:#eee;max-width:900px;margin:0 auto}h1{color:#a29bfe}h2{color:#74b9ff;margin-top:28px}.card{background:#2d2d44;padding:20px;border-radius:8px;margin:12px 0}.badge{display:inline-block;padding:4px 12px;border-radius:20px;font-weight:bold}.grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}.metric{background:#1e1e35;padding:14px;border-radius:6px;text-align:center}.val{font-size:26px;font-weight:bold;color:#a29bfe}.lbl{font-size:11px;color:#aaa;margin-top:4px}.two{display:grid;grid-template-columns:1fr 1fr;gap:12px}pre{background:#111;padding:14px;border-radius:6px;overflow:auto;max-height:500px;font-size:11px}a{color:#74b9ff}</style></head><body><h1>Chatwoot Reports – Cache Status</h1><div class="card"><p>Status: <span class="badge" style="background:${sc};color:#000">${sl}</span> &nbsp; ${ageMinutes} min old &nbsp; ${sz} KB</p><div class="two"><div><b>Metrics updated:</b><br>${esc(data._metricsAt ?? 'never')}</div><div><b>Static data updated:</b><br>${esc(data._staticAt ?? 'never — run Static workflow')}</div></div><p style="margin-top:12px">Next refresh: ${esc(data._nextRefresh ?? 'unknown')} &nbsp;|&nbsp; <a href="/webhook/chatwoot-reports" target="_blank">JSON endpoint</a></p></div><h2>Summary</h2><div class="grid"><div class="metric"><div class="val">${esc(summary.totalConversations)}</div><div class="lbl">Conversations</div></div><div class="metric"><div class="val">${esc(summary.resolved)}</div><div class="lbl">Resolved</div></div><div class="metric"><div class="val">${esc(summary.avgResolutionTime)}</div><div class="lbl">Avg Resolution</div></div><div class="metric"><div class="val">${(data.agents??[]).length}</div><div class="lbl">Agents</div></div><div class="metric"><div class="val">${(data.teams??[]).length}</div><div class="lbl">Teams</div></div><div class="metric"><div class="val">${(data.inboxes??[]).length}</div><div class="lbl">Inboxes</div></div></div><h2>Raw Payload</h2><pre>${esc(JSON.stringify(data, null, 2))}</pre></body></html>`;

return [{ json: { html } }];
